# 只追加语文和数学，如果文件不存在则创建
lines = []
lines.append("'高三': {")

prefix_map = {'语文': 'yuwen', '数学': 'shuxue'}

# 简化：如果文件不存在，生成全部语文数学
if not os.path.exists(path):
    for subj, items in subjects.items():
        prefix = prefix_map.get(subj, '')
        if not items:
            continue
        lines.append(f"    '{subj}': [")
        for i, (ch, name, content) in enumerate(items, 1):
            comma = ',' if i < len(items) else ''
            lines.append(f"        {{ id: '{prefix}-g3-{i}', chapter: '{ch}', name: '{name}', content: '{content}' }}{comma}")
        lines.append("    ],")
    lines.append("}")
    with open(path, 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines) + '\n')
    print(f'已生成: {path}')
    print(f'文件大小: {os.path.getsize(path)} 字节')
else:
    print(f'文件已存在: {path}')
    print(f'文件大小: {os.path.getsize(path)} 字节')

